solution_code:
#include <iostream>

int sumOf(int a, int b)
{
    return a + b;
}

int productOf(int a, int b)
{
    return a * b;
}

int main()
{
    int a, b;
    std::cin >> a >> b;
    std::cout << sumOf(a, b) << "\n";
    std::cout << productOf(a, b) << "\n";
    return 0;
}

